     1→import { NavigationProp, useNavigation } from '@react-navigation/native';
     2→import { useCallback, useMemo } from 'react';
     3→import { KEY_NAME_TO_ICON, NAME_TO_ICON, getNormalizedKeyName } from '../../../screens/Points/data';
     4→import { PointsProduct } from '../../../redux/ducks/points';
     5→import { PointsCardItem } from '../../../screens/Points/Models';
     6→import { extractRawProducts, isValidProduct, normalizeName } from './data';
     7→import { PointsCardItemBuilder } from './data/pointsCardItemBuilder';
     8→import { PropsRootStack } from '../../../routes/Models';
     9→import { eventSelectContent } from '~/constants/functions';
    10→
    11→export const useCardBuilderWhereUseMyPoints = () => {
    12→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    13→
    14→  const onPressKeyName = useMemo(
    15→    () => ({
    16→      [normalizeName(KEY_NAME_TO_ICON.MARKETPLACE)]: () => {
    17→        navigation.navigate('RewardProgramMarketplace');
    18→      },
    19→      [normalizeName(KEY_NAME_TO_ICON.RESCUE_IN_INVOICE)]: () => {
    20→        navigation.navigate('InvoiceCashbackOnboarding');
    21→      },
    22→      [normalizeName(KEY_NAME_TO_ICON.FUEL_VOUCHER)]: () => {},
    23→      [normalizeName(KEY_NAME_TO_ICON.MONTHLY_DISCOUNT)]: () => {},
    24→      [normalizeName(KEY_NAME_TO_ICON.CAR_INSURANCE_DISCOUNT)]: () => {},
    25→      [normalizeName(KEY_NAME_TO_ICON.PARKING_DISCOUNT)]: () => {},
    26→      [normalizeName(KEY_NAME_TO_ICON.FINES_DISCOUNT)]: () => {},
    27→      [normalizeName(KEY_NAME_TO_ICON.IPVA_DISCOUNT)]: () => {},
    28→      [normalizeName(KEY_NAME_TO_ICON.AIRLINE_MILES)]: () => {},
    29→    }),
    30→    [navigation]
    31→  );
    32→
    33→  const handleOnPress = useCallback(
    34→    (keyName: string) => {
    35→      return () => {
    36→        if (keyName in onPressKeyName) {
    37→          onPressKeyName[keyName]();
    38→          const contentIdName = getNormalizedKeyName(keyName).split(' ').join('_').toLowerCase();
    39→
    40→          eventSelectContent({
    41→            content_type: 'cta',
    42→            content_id: `onde_usar_${contentIdName}`,
    43→            location_1: 'monetizacao',
    44→            location_2: 'hub_recompensas_spmais',
    45→            location_3: 'saiba_mais',
    46→          });
    47→        }
    48→      };
    49→    },
    50→    [onPressKeyName]
    51→  );
    52→
    53→  const buildPointsCardItems = useCallback(
    54→    (pointsOptions: PointsProduct[] | undefined): PointsCardItem[] => {
    55→      const rawProducts = extractRawProducts(pointsOptions);
    56→      const builder = PointsCardItemBuilder.getInstance();
    57→
    58→      return rawProducts.filter(isValidProduct).map((product, index) => {
    59→        const normalizedName = normalizeName(product.name);
    60→        const icon = NAME_TO_ICON[normalizedName] || 'icon-default';
    61→
    62→        const isCashbackInInvoice =
    63→          normalizedName === normalizeName(KEY_NAME_TO_ICON.RESCUE_IN_INVOICE);
    64→        const onPress = isCashbackInInvoice
    65→          ? () => {
    66→              const rawCF =
    67→                (product as any).conversionFactor ?? (product as any).convertionFactor ?? 0;
    68→              const conversionFactor = (() => {
    69→                if (typeof rawCF === 'number') return rawCF;
    70→                if (typeof rawCF === 'string') {
    71→                  const n = Number(
    72→                    String(rawCF)
    73→                      .replace(',', '.')
    74→                      .replace(/[^0-9.-]/g, '')
    75→                  );
    76→                  return Number.isFinite(n) ? n : 0;
    77→                }
    78→                return 0;
    79→              })();
    80→              const productCode = (product as any).productCode ?? (product as any).code;
    81→              const campaingId =
    82→                (product as any).campaingId ?? (product as any).campaignId ?? undefined;
    83→              navigation.navigate('InvoiceCashbackOnboarding', {
    84→                conversionFactor,
    85→                productCode,
    86→                campaingId,
    87→              });
    88→            }
    89→          : handleOnPress(normalizedName);
    90→
    91→        return builder
    92→          .reset()
    93→          .setId(index + 1)
    94→          .setText(product.name)
    95→          .setIcon(icon)
    96→          .setOnPress(onPress)
    97→          .build();
    98→      });
    99→    },
   100→    [handleOnPress]
   101→  );
   102→
   103→  return buildPointsCardItems;
   104→};
